### 7. PIPELINE REGISTRATION AND FACTORY FUNCTION

**The `pipeline()` function (Lines 3446-3513):**

```javascript
export async function pipeline(
    task,
    model = null,
    {
        progress_callback = null,
        config = null,
        cache_dir = null,
        local_files_only = false,
        revision = 'main',
        device = null,
        dtype = null,
        subfolder = 'onnx',
        use_external_data_format = null,
        model_file_name = null,
        session_options = {},
    } = {}
) {
    // Apply aliases
    task = TASK_ALIASES[task] ?? task;

    // Get pipeline info from SUPPORTED_TASKS
    const pipelineInfo = SUPPORTED_TASKS[task.split('_', 1)[0]];
    if (!pipelineInfo) {
        throw Error(`Unsupported pipeline: ${task}. Must be one of [${Object.keys(SUPPORTED_TASKS)}]`)
    }

    // Use provided model or default
    if (!model) {
        model = pipelineInfo.default.model
        console.log(`No model specified. Using default model: "${model}".`);
    }

    const pretrainedOptions = {
        progress_callback,
        config,
        cache_dir,
        local_files_only,
        revision,
        device,
        dtype,
        subfolder,
        use_external_data_format,
        model_file_name,
        session_options,
    }

    // Create mapping of what to load
    const classes = new Map([
        ['tokenizer', pipelineInfo.tokenizer],
        ['model', pipelineInfo.model],
        ['processor', pipelineInfo.processor],
    ]);

    // Load model, tokenizer, and processor (in parallel)
    const results = await loadItems(classes, model, pretrainedOptions);
    results.task = task;

    dispatchCallback(progress_callback, {
        'status': 'ready',
        'task': task,
        'model': model,
    });

    // Instantiate the pipeline class
    const pipelineClass = pipelineInfo.pipeline;
    return new pipelineClass(results);
}
```

**How it works:**
1. User calls: `await pipeline('image-to-text', 'Xenova/vit-gpt2-image-captioning')`
2. Task name is validated against `SUPPORTED_TASKS`
3. Pipeline info is retrieved from `SUPPORTED_TASKS[task]`
4. Model, tokenizer, and processor classes are loaded in parallel using `loadItems()`
5. Results (tokenizer, model, processor instances) are passed to pipeline constructor
6. Pipeline instance is returned to user

